configuration.jsScript:
if (metadata.entityType && metadata.entityType !== 'DEVICE') {
  return false;
}
var profile = metadata.deviceType || '';
return profile === 'milesight-am308' || profile === 'milesight-ws302';

var tgEnabled = (metadata.telegram_enabled === 'true');
if (!tgEnabled) return false;
if (!metadata.telegram_botToken || !metadata.telegram_chatId) return false;

// Helper: get first defined value from msg using multiple possible key names
function val(keys) {
  for (var i = 0; i < keys.length; i++) {
    if (msg[keys[i]] !== undefined) return Number(msg[keys[i]]);
  }
  return undefined;
}

var aqEnabled = (metadata.airQuality_enabled === 'true');
if (aqEnabled) {
  var co2 = val(['co2', 'data_CO2', 'data_co2', 'CO2']);
  if (co2 !== undefined && metadata.co2Max && co2 >= Number(metadata.co2Max)) return true;
  var pm25 = val(['pm25', 'data_PM25', 'data_pm25', 'PM25', 'data_PM2_5', 'pm2_5']);
  if (pm25 !== undefined && metadata.pm25Max && pm25 >= Number(metadata.pm25Max)) return true;
  var pm10 = val(['pm10', 'data_PM10', 'data_pm10', 'PM10']);
  if (pm10 !== undefined && metadata.pm10Max && pm10 >= Number(metadata.pm10Max)) return true;
  var tvoc = val(['tvoc', 'data_TVOC', 'data_tvoc', 'TVOC']);
  if (tvoc !== undefined && metadata.tvocMax && tvoc >= Number(metadata.tvocMax)) return true;
  var temp = val(['temperature', 'temp', 'data_temperature', 'data_temp', 'data_Temperature']);
  if (temp !== undefined && metadata.tempMax && temp >= Number(metadata.tempMax)) return true;
  var hum = val(['humidity', 'hum', 'data_humidity', 'data_hum', 'data_Humidity']);
  if (hum !== undefined && metadata.humMax && hum >= Number(metadata.humMax)) return true;
  var press = val(['pressure', 'data_pressure', 'data_Pressure', 'barometric_pressure']);
  if (press !== undefined && metadata.pressMax && press >= Number(metadata.pressMax)) return true;
}

var noiseEnabled = (metadata.noise_enabled === 'true');
if (noiseEnabled) {
  var laeq = val(['laeq', 'data_LAeq', 'data_laeq', 'LAeq']);
  if (laeq !== undefined && metadata.laeqMax && laeq >= Number(metadata.laeqMax)) return true;
  var lai = val(['lai', 'data_LAI', 'data_lai', 'LAI']);
  if (lai !== undefined && metadata.laiMax && lai >= Number(metadata.laiMax)) return true;
  var laimax = val(['laimax', 'data_LAImax', 'data_laimax', 'LAImax']);
  if (laimax !== undefined && metadata.laimaxMax && laimax >= Number(metadata.laimaxMax)) return true;
}

var leak = val(['waterLeak', 'leak', 'data_leak', 'water_leak']);
if (leak === 1) return true;

return false;

configuration.alarmDetailsBuildJs:
var details = {};
details.deviceName = metadata.deviceName;
for (var key in msg) {
  if (msg.hasOwnProperty(key)) {
    details[key] = msg[key];
  }
}
return details;

configuration.jsScript:
var tg = {
  botToken: metadata.telegram_botToken,
  chatId: metadata.telegram_chatId,
  topicId: metadata.telegram_topicId
};
var rawDeviceName = metadata.deviceName || 'Unknown Device';
var deviceName = rawDeviceName;
var parts = rawDeviceName.split('-');
if (parts.length >= 5) {
  var model = parts[2];
  var seq = parts[3];
  var room = parts[4];
  var sensorType = model;
  if (model.indexOf('AM308') !== -1) {
    sensorType = 'Indoor Ambience Sensor';
  } else if (model.indexOf('WS302') !== -1) {
    sensorType = 'Sound Level Sensor';
  }
  deviceName = sensorType + ' (Room ' + room + ')';
}

function val(keys) {
  for (var i = 0; i < keys.length; i++) {
    if (msg[keys[i]] !== undefined) return Number(msg[keys[i]]);
    if (msg.details && msg.details[keys[i]] !== undefined) return Number(msg.details[keys[i]]);
  }
  return undefined;
}

var alerts = [];
var aqEnabled = (metadata.airQuality_enabled === 'true');
var noiseEnabled = (metadata.noise_enabled === 'true');

if (aqEnabled) {
  var co2 = val(['co2', 'data_CO2', 'data_co2', 'CO2']);
  if (co2 !== undefined && metadata.co2Max && co2 >= Number(metadata.co2Max)) alerts.push('• <b>CO₂:</b> ' + co2 + ' ppm (limit: ' + metadata.co2Max + ' ppm)');
  var pm25 = val(['pm25', 'data_PM25', 'data_pm25', 'PM25', 'data_PM2_5', 'pm2_5']);
  if (pm25 !== undefined && metadata.pm25Max && pm25 >= Number(metadata.pm25Max)) alerts.push('• <b>PM2.5:</b> ' + pm25 + ' ug/m3 (limit: ' + metadata.pm25Max + ' ug/m3)');
  var pm10 = val(['pm10', 'data_PM10', 'data_pm10', 'PM10']);
  if (pm10 !== undefined && metadata.pm10Max && pm10 >= Number(metadata.pm10Max)) alerts.push('• <b>PM10:</b> ' + pm10 + ' ug/m3 (limit: ' + metadata.pm10Max + ' ug/m3)');
  var tvoc = val(['tvoc', 'data_TVOC', 'data_tvoc', 'TVOC']);
  if (tvoc !== undefined && metadata.tvocMax && tvoc >= Number(metadata.tvocMax)) alerts.push('• <b>TVOC:</b> ' + tvoc + ' ppb (limit: ' + metadata.tvocMax + ' ppb)');
  var temp = val(['temperature', 'temp', 'data_temperature', 'data_temp', 'data_Temperature']);
  if (temp !== undefined && metadata.tempMax && temp >= Number(metadata.tempMax)) alerts.push('• <b>Temp:</b> ' + temp + ' C (limit: ' + metadata.tempMax + ' C)');
  var hum = val(['humidity', 'hum', 'data_humidity', 'data_hum', 'data_Humidity']);
  if (hum !== undefined && metadata.humMax && hum >= Number(metadata.humMax)) alerts.push('• <b>Humidity:</b> ' + hum + '% (limit: ' + metadata.humMax + '%)');
  var press = val(['pressure', 'data_pressure', 'data_Pressure', 'barometric_pressure']);
  if (press !== undefined && metadata.pressMax && press >= Number(metadata.pressMax)) alerts.push('• <b>Pressure:</b> ' + press + ' hPa (limit: ' + metadata.pressMax + ' hPa)');
}

if (noiseEnabled) {
  var laeq = val(['laeq', 'data_LAeq', 'data_laeq', 'LAeq']);
  if (laeq !== undefined && metadata.laeqMax && laeq >= Number(metadata.laeqMax)) alerts.push('• <b>LAeq:</b> ' + laeq + ' dBA (limit: ' + metadata.laeqMax + ' dBA)');
  var lai = val(['lai', 'data_LAI', 'data_lai', 'LAI']);
  if (lai !== undefined && metadata.laiMax && lai >= Number(metadata.laiMax)) alerts.push('• <b>LAI:</b> ' + lai + ' dBA (limit: ' + metadata.laiMax + ' dBA)');
  var laimax = val(['laimax', 'data_LAImax', 'data_laimax', 'LAImax']);
  if (laimax !== undefined && metadata.laimaxMax && laimax >= Number(metadata.laimaxMax)) alerts.push('• <b>LAImax:</b> ' + laimax + ' dBA (limit: ' + metadata.laimaxMax + ' dBA)');
}

var leak = val(['waterLeak', 'leak', 'data_leak', 'water_leak']);
if (leak === 1) alerts.push('• <b>🚨 WATER LEAK DETECTED!</b>');

var dateStr = '';
try {
  var ts = Number(msg.startTs || Date.now());
  dateStr = new Date(ts).toISOString().replace('T', ' ').substring(0, 19) + ' UTC';
} catch (e) {
  dateStr = new Date().toISOString().replace('T', ' ').substring(0, 19) + ' UTC';
}

var text = '🚨 <b>ALERT: Threshold Breached</b>\n🏨 <b>Device:</b> ' + deviceName + '\n⏱ <b>Time:</b> ' + dateStr + '\n\n<b>Details:</b>\n' + alerts.join('\n');
var body = { chat_id: tg.chatId, text: text, parse_mode: 'HTML' };
if (tg.topicId) body.message_thread_id = parseInt(tg.topicId);

metadata.telegramBotToken = tg.botToken;
return {msg: body, metadata: metadata, msgType: msgType};
